mapper.select:
SELECT id, tenant_id, template_id, field_name, field_value, submitter_id, frequency, last_used_at, updated_at
FROM form_field_value_stats
WHERE template_id = #{templateId} AND field_name = #{fieldName}
      AND field_value = #{fieldValue} AND submitter_id = #{submitterId}
      AND tenant_id = #{tenantId}

SELECT id, tenant_id, template_id, field_name, field_value, submitter_id, frequency, last_used_at, updated_at
FROM form_field_value_stats
WHERE template_id = #{templateId} AND field_name = #{fieldName} AND submitter_id = #{submitterId}
      AND tenant_id = #{tenantId}
ORDER BY frequency DESC, last_used_at DESC

SELECT id, tenant_id, template_id, field_name, field_value, submitter_id, frequency, last_used_at, updated_at
FROM form_field_value_stats
WHERE template_id = #{templateId} AND field_name = #{fieldName} AND submitter_id = #{submitterId}
      AND tenant_id = #{tenantId}
ORDER BY frequency DESC, last_used_at DESC
LIMIT #{limit}

SELECT id, tenant_id, template_id, field_name, field_value, submitter_id, frequency, last_used_at, updated_at
FROM form_field_value_stats
WHERE template_id = #{templateId} AND field_name = #{fieldName} AND submitter_id = '__GLOBAL__'
      AND tenant_id = #{tenantId}
ORDER BY frequency DESC, last_used_at DESC
LIMIT #{limit}

SELECT id, tenant_id, template_id, field_name, field_value, submitter_id, frequency, last_used_at, updated_at
FROM form_field_value_stats
WHERE template_id = #{templateId} AND field_name = #{fieldName}
  AND submitter_id != '__GLOBAL__'
  AND tenant_id = #{tenantId}
ORDER BY submitter_id, frequency DESC
